using System.Collections;
using UnityEngine;

/// <summary>
/// Rolamento (ROL do GDD — habilidade central do Pangolim):
///
/// Ao premir o botão de habilidade (em terra, fora de cooldown), o player
/// rola na direcção em que está virado durante 'rollDuration' a 'rollSpeed'
/// (mesmo padrão de DashAbility/ChargeAbility — bloqueia o movimento normal e
/// move o Rigidbody2D directamente). Enquanto a rolar:
///
/// - <see cref="IsRolling"/> fica true — PlayerCombat.TryDamagePlayer consulta
///   isto e chama <see cref="ApplyRollDefense"/> para aplicar o bónus de
///   defesa da ficha (rollDefenseBonus), tal como o ShellGuard da Tartaruga.
/// - Animator.SetBool("IsRolling", true) activa a animação de rolamento.
/// - Inimigos dentro de 'rollPushRadius' (à frente do player) são empurrados
///   via EnemyHealth.ApplyExternalKnockback (sem causar dano — só empurrão).
/// - Blocos empurráveis (PushableBlock) continuam a reagir normalmente ao
///   contacto/PushStrength da forma, como em qualquer movimento.
///
/// Tem cooldown (rollCooldown) e Cancel(), tal como Dash/Charge — interrompe
/// o rolamento em curso (morte, transformação, etc.).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class RollAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private const int MaxPushTargets = 8;
    private static readonly Collider2D[] PushBuffer = new Collider2D[MaxPushTargets];

    private bool enabledForForm;
    private AnimalFormData form;
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private float cooldownTimer;
    private Coroutine rollRoutine;

    /// <summary>true enquanto o player está a rolar — consultado por PlayerCombat.TryDamagePlayer.</summary>
    public bool IsRolling { get; private set; }

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && (form.canRoll || form.primaryAbility == PrimaryAbility.Roll);

        if (!enabledForForm) StopRollIfRunning();
    }

    /// <summary>Chamado pelo AbilityRouter (OnAbilityPressed) quando a forma tem PrimaryAbility.Roll.</summary>
    public void TryRoll()
    {
        if (!enabledForForm) return;
        if (cooldownTimer > 0f) return;
        if (rollRoutine != null) return;
        if (motor.MovementLocked) return;
        if (!motor.IsGrounded) return;

        rollRoutine = StartCoroutine(RollRoutine());
    }

    private IEnumerator RollRoutine()
    {
        cooldownTimer = form.rollCooldown;

        IsRolling = true;
        motor.SetMovementLocked(true, this);
        motor.Anim?.SetBool("IsRolling", true);

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;

        float elapsed = 0f;
        while (elapsed < form.rollDuration)
        {
            rb.velocity = new Vector2(dir * form.rollSpeed, rb.velocity.y);
            PushNearbyEnemies(dir);

            elapsed += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        EndRoll();
    }

    /// <summary>Empurra (sem dano) inimigos dentro de 'rollPushRadius' à frente do player.</summary>
    private void PushNearbyEnemies(int dir)
    {
        if (form.rollPushForce <= 0f) return;

        Vector2 origin = (Vector2)transform.position + new Vector2(dir * form.rollPushRadius * 0.5f, 0f);
        int count = Physics2D.OverlapCircleNonAlloc(origin, form.rollPushRadius, PushBuffer);

        for (int i = 0; i < count; i++)
        {
            var col = PushBuffer[i];
            if (col == null) continue;

            var enemyHealth = col.GetComponent<EnemyHealth>();
            if (enemyHealth == null) continue;

            enemyHealth.ApplyExternalKnockback(transform.position, form.rollPushForce);
        }

        // Limpar referências no buffer após uso — evita reter objetos destruídos entre rolamentos.
        System.Array.Clear(PushBuffer, 0, count);
    }

    private void EndRoll()
    {
        IsRolling = false;
        motor.Anim?.SetBool("IsRolling", false);
        motor.SetMovementLocked(false, this);
        rollRoutine = null;
    }

    private void StopRollIfRunning()
    {
        if (rollRoutine == null) return;

        StopCoroutine(rollRoutine);
        EndRoll();
    }

    /// <summary>Aplica o bónus de defesa do rolamento (chamado por PlayerCombat.TryDamagePlayer).</summary>
    public int ApplyRollDefense(int damage)
    {
        if (!IsRolling || form == null) return damage;
        return form.ApplyDefense(damage, form.rollDefenseBonus);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    void IAbility.Activate() => TryRoll();
    void IAbility.Release() { } // rolamento não tem "soltar"

    /// <summary>Interrompe o rolamento em curso (morte, transformação, etc.).</summary>
    public void Cancel(AbilityCancelReason reason) => StopRollIfRunning();

    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => rollRoutine != null;
    public float CooldownDuration => form != null ? form.rollCooldown : 0f;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && rollRoutine == null && !motor.MovementLocked;

    /// <summary>AnimalsDebugPanel — zera o cooldown do rolamento.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
